function memoize(fn) {
  // Separate caches for different key types
  const primitiveCache = new Map(); // For primitives (safe)
  const objectCache = new WeakMap(); // For objects (allows GC)

  return function(...args) {
    // For simplicity, handle single argument case
    const arg = args[0];

    // Determine if argument is object or primitive
    const isObject = typeof arg === 'object' && arg !== null;

    if (isObject) {
      // Use WeakMap for objects
      if (objectCache.has(arg)) {
        return objectCache.get(arg);
      }

      const result = fn.apply(this, args);
      objectCache.set(arg, result);
      return result;
    } else {
      // Use Map for primitives
      if (primitiveCache.has(arg)) {
        return primitiveCache.get(arg);
      }

      const result = fn.apply(this, args);
      primitiveCache.set(arg, result);
      return result;
    }
  };
}

module.exports = memoize;
EOF

